ac:structured-macro.ac:plain-text-body:
@startuml
skinparam backgroundColor #FAFAFA
skinparam defaultFontName Arial
skinparam defaultFontSize 11
skinparam activityBackgroundColor #EEF4FF
skinparam activityBorderColor #3366CC

title Research Cycle — Full Pipeline (Every 15 Minutes)

start

partition "Phase 1: Data Collection (Sequential)" {
  :Start shared Playwright browser session\n(required for Maya WAF bypass);
  :Refresh Maya company cache\n(500 companies, 24h TTL);
  :Fetch latest 100 Maya filings\nEach → Signal(TASE{id}, maya_type);
  :Fetch full text for 2 high-value\ninstitutional filings (deal size, stake %);
  :Fetch earnings calendar\n(events within 10 days → earnings_calendar signal);
  :Check 13 dual-listed stocks overnight\n(move ≥ 2% → dual_listed_move signal);
  :Read 8 Israeli RSS feeds\n(Hebrew name regex → company signal);
  :Read 3 global headline feeds\n(Yahoo/MarketWatch/WSJ — context text only);
  :Fetch macro snapshot\n(TA-125, S&P, Nasdaq, USD/ILS, VIX, WTI, US10Y);
  :Compute sector rotation labels\n(BULL+/BULL/NEUTRAL/BEAR/BEAR-);
  :Run SignalEnricher\n(upgrade GENERAL signals via keywords);
}

partition "Phase 2: Sector Agents (Parallel — 4 workers)" {
  fork
    :BanksAgent;
  fork again
    :TechDefenseAgent;
  fork again
    :EnergyAgent;
  fork again
    :PharmaAgent;
  end fork
  fork
    :RealEstateAgent;
  fork again
    :TelecomConsumerAgent;
  fork again
    :DiscoveryAgent\n(~500 tickers);
  end fork

  note right
    Each agent runs 9 steps:
    1. Filter signals for this sector
    2. MarketAnomalyDetector (8 detectors)
    3. Sector-specific macro signals
    4. Preliminary ConvergenceEngine
    5. Drop tickers with score = 0
    6. Web news for top-5 (Google News RSS)
    7. Re-run ConvergenceEngine
    8. DeepStockAnalyzer (top-8)
    9. Sector LLM call → ranked portfolio
  end note
}

partition "Phase 3: Manager Arbitration (Sequential)" {
  :ResearchManager collects all sector portfolios;
  :CIO LLM arbitrates — picks Stock of the Week;
  :Apply cross-sector rules\n(no 2 from same sector unless score > 90);
}

partition "Output" {
  if (score > 0 after arbitration?) then (yes)
    :Send Telegram quick alert\n(top N stocks);
  endif
  if (after 17:00 Israel time?) then (yes)
    :Send daily summary;
  endif
  if (Thursday 17:00?) then (yes)
    :Send weekly report with full rationale;
  endif
  :Update excel_memory.xlsx\n(3 sheets);
  :Save state.json;
}

:Sleep until next cycle\n(default: 15 min);
stop
@enduml

{
  "stock_of_the_week": {
    "ticker":          "ESLT.TA",
    "name":            "Elbit Systems",
    "score":           87,
    "full_rationale":  "...",
    "key_catalyst":    "New IDF drone contract, NIS 320M, representing 4% of annual revenue",
    "technical_setup": "Breakout above 52w high on 3x average volume",
    "main_risk":       "Ceasefire announcement could trigger sector rotation out of defense",
    "keywords":        ["defense", "contract", "volume_spike", "breakout"]
  },
  "runners_up": [
    {"ticker": "NVMI.TA", "name": "Nova Ltd", "score": 71, "summary": "...", "key_catalyst": "..."},
    {"ticker": "TEVA.TA", "name": "Teva Pharma", "score": 66, "summary": "...", "key_catalyst": "..."}
  ],
  "macro_context": "USD/ILS at 3.72 (shekel weak) — favors exporters. WTI at $82 — energy names bid.",
  "week_theme":    "Defense + Semis outperforming on security escalation + US tariff news",
  "sector_in_focus": "TechDefense"
}

@startuml skinparam backgroundColor #FAFAFA skinparam defaultFontName Arial skinparam defaultFontSize 11
title ConvergenceEngine — Score Calculation Flow
start
:Collect all signals for one ticker\n(maya, market anomaly, news, web news);
:Sum base scores\nbase = Σ BASE_SCORES[signal_type];
note right Top base scores: maya_ipo = 50 new_contract = 45 regulatory_approval = 42 institutional_investor = 40 breakout = 35 dual_listed_move = 35 earnings (web) = 35 volume_spike = 28 price_move = 30 end note
:Find best pairwise multiplier\nmultiplier = max(MULTIPLIERS[t1,t2]) for any pair in signals;
note right Top multipliers: earnings_calendar + volume_spike = 2.5x low_reversal + earnings_calendar = 2.4x oversold_bounce + earnings_calendar = 2.3x earnings + volume_spike = 2.3x relative_strength + earnings_calendar = 2.2x end note
if (earnings_calendar signal present?) then (yes) :Add earnings proximity gradient\n(dte=0 → +80, dte=1 → +70, dte=2 → +60\n dte=3 → +45, dte≤7 → +25, dte≤14 → +12); endif
:Count distinct signal categories\n(fundamental, technical, news, macro);
if (3 or more categories?) then (yes) :Apply 3-category bonus\nmultiplier × 1.3; endif
:final_score = base × multiplier;
note right Expected distribution: 38–58 = monitor / informational 65–81 = strong buy candidate 85–100 = exceptional (≤1/month) end note
stop @enduml

@startuml skinparam backgroundColor #FAFAFA skinparam defaultFontName Arial skinparam defaultFontSize 11
title Telegram Bot — Message Routing & Q&A Pipeline
actor User as U participant "BotServer\n(daemon thread)" as BS participant "CommandHandler\n(14 commands)" as CMD participant "QAPipeline" as QA participant "LLMAnalyst\nplan_intent()" as INTENT participant "Tool Registry\n(11 tools)" as TOOLS participant "LLMAnalyst\nchat_answer()" as ANSWER database "Shared State\n(RLock)" as STATE
U -> BS : Telegram message BS -> BS : Check 10s cooldown per chat BS -> BS : Send "Analyzing..." placeholder
alt Starts with "/" BS -> CMD : handle_command(message) CMD -> STATE : read or mutate settings CMD --> U : command response else Free text BS -> QA : answer(chat_id, question) QA -> STATE : deepcopy() [lock held <5ms]
QA -> INTENT : plan_intent(question, tickers, tools) INTENT --> QA : {ticker, intent, tools[], language}
alt ticker is null AND stock-specific intent QA -> INTENT : resolve_ticker(question, company_list) note right: Hebrew company name → .TA symbol\n(confidence ≥ 0.6 required) INTENT --> QA : {ticker, company_name, confidence} end
loop for each tool in plan.tools QA -> TOOLS : run(tool_name, ticker, state_copy) TOOLS --> QA : context string end
QA -> ANSWER : chat_answer(question, context, language, history) ANSWER --> QA : 3-6 sentence answer QA -> BS : split at paragraph boundaries (≤4096 chars/chunk) BS --> U : answer chunks BS -> BS : append to chat_history[chat_id]\n(keep last 8 messages) end
@enduml
